INSERT INTO brands (slug, name, context, products_context, elevenlabs_voice_id) VALUES

('apice', 'Ápice',
'Ápice é uma marca de beleza premium brasileira voltada para mulheres de 25-45 anos que buscam skincare e cosméticos de alta performance. Tom de voz: sofisticado, confiante, educativo mas acessível. Persona: mulher moderna, urbana, que investe em si mesma. DO: falar de ingredientes, resultados visíveis, ciência por trás do produto, antes e depois, rotina de skincare. DON''T: linguagem muito informal, gírias excessivas, comparação negativa com concorrentes.',
'Linha Sérum Vitamina C (principais SKUs: Sérum Vitamina C 30ml, Sérum Vitamina C 60ml), Creme Anti-idade Redentor, Hidratante Facial FPS50, Tônico Equilibrante, Máscara Detox de Argila, Óleo Facial de Rosas, Protetor Solar Luminous, Esfoliante Suave Iluminador. Categorias: Skincare básico, Tratamento, Proteção solar, Limpeza facial.',
'pNInz3Z91uDbnQZ3B4aQ'),

('rituaria', 'Rituaria',
'Rituaria é uma marca de wellness e autocuidado para mulheres que buscam rituais de beleza com propósito e conexão com a natureza. Tom de voz: acolhedor, poético, inspiracional, sustentável. Persona: mulher consciente, que valoriza slow living, ingredientes naturais e rituais de autocuidado como pausa no dia. DO: falar de ritual, pausa, ingredientes naturais, aromas, experiência sensorial, sustentabilidade, intenção. DON''T: linguagem fria ou técnica demais, foco excessivo em resultados rápidos, promessas agressivas.',
'Óleo de Banho Lavanda & Camomila, Esfoliante Corporal de Açúcar e Baunilha, Creme Corporal Manteiga de Karité, Vela Aromática (linha Ritual da Noite, Ritual da Manhã), Sabonete Artesanal em Barra, Hidratante Corporal Floral, Bruma Corporal Perfumada, Kit Ritual do Banho. Categorias: Cuidados corporais, Aromaterapia, Rituais de banho, Velas e difusores.',
'EXAVITQu4vr4xnSDe4oz'),

('gocase', 'Gocase',
'Gocase é uma marca de acessórios criativos para smartphones, notebooks e lifestyle. Tom de voz: descolado, jovem, divertido, criativo e ousado. Persona: geração Z e millennials que expressam personalidade pelos acessórios e usam tech no dia a dia. DO: falar de personalização, estilo de vida, criatividade, pop culture, funcionalidade + estilo, drops limitados. DON''T: tom sério demais, falar como corporativo, ignorar trends e referências culturais.',
'Capas para iPhone (linha Clear, Silicone, MagSafe, Personalizada), Capas para Samsung, Cases para MacBook, Mochilas e Bolsas Tech, Acessórios MagSafe (carteira, suporte), Pelúcias Colecionáveis, Carregadores e Cabos Coloridos, Fones de Ouvido Estilizados. Categorias: Capas para celular, Cases para notebook, Acessórios tech, Lifestyle.',
'onwK4e9ZLuTAKqWW03F9');
